'use client';

import { Plus, Clock, ChevronRight } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/Button';
import { motion } from 'framer-motion';
import { cn } from '@/lib/utils';
import { useState } from 'react';

export default function CustomerDashboard() {
    const router = useRouter();
    // const [isMenuOpen, setIsMenuOpen] = useState(false); // Unused currently

    // Dummy Data
    const user = {
        name: "Alexander Sterling",
        location: "San Francisco, CA",
        avatar: "https://i.pravatar.cc/150?u=alexander",
        totalPosted: 128,
        rating: 4.9,
        pendingJobs: 4
    };

    const activeJobs = [
        {
            id: '1',
            title: 'Full-Stack System Migration',
            status: 'IN PROGRESS',
            dueDate: 'Due in 4 days',
            progress: 65,
            image: 'https://images.unsplash.com/photo-1558441366-4f40445d8b8b?auto=format&fit=crop&w=400&q=80'
        },
        {
            id: '2',
            title: 'Cloud Infrastructure Audit',
            status: 'AUDITING',
            dueDate: 'Started today',
            progress: 25,
            image: 'https://images.unsplash.com/photo-1558494949-0d35069a794c?auto=format&fit=crop&w=400&q=80'
        }
    ];

    return (
        <div className="bg-background min-h-screen pb-24 text-foreground transition-colors duration-300 max-w-md mx-auto shadow-2xl overflow-hidden border-x border-border relative">
            {/* Background Ambient Glow */}
            <div className="absolute top-0 left-0 w-full h-96 bg-primary/5 rounded-b-[3rem] pointer-events-none z-0" />

            {/* Header */}
            <div className="p-6 relative z-10 pt-8">
                <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center gap-3 bg-secondary/50 backdrop-blur-md p-2 pr-4 rounded-full border border-border/50 shadow-sm">
                        <div className="w-8 h-8 rounded-full bg-emerald-500/10 flex items-center justify-center border border-emerald-500/20">
                            <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse shadow-lg shadow-emerald-500/40"></div>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[9px] text-muted-foreground font-bold uppercase tracking-wider">Current Location</span>
                            <span className="text-xs font-bold text-foreground leading-none max-w-[140px] truncate">{user.location}</span>
                        </div>
                    </div>
                    <button
                        onClick={() => router.push('/dashboard/profile')}
                        className="w-11 h-11 rounded-full overflow-hidden border-2 border-background ring-2 ring-border shadow-lg active:scale-95 transition-transform"
                    >
                        <img src={user.avatar} alt="Profile" className="w-full h-full object-cover" />
                    </button>
                </div>

                {/* Greeting & Title */}
                <div className="mb-8 space-y-1">
                    <h2 className="text-sm font-bold text-muted-foreground uppercase tracking-wider">Welcome back</h2>
                    <h1 className="text-3xl font-black text-foreground tracking-tight">Find Services</h1>
                </div>

                {/* Favorites */}
                <div className="mb-8">
                    <div className="flex justify-between items-end mb-4">
                        <h2 className="text-sm font-bold text-foreground">Your Favorites</h2>
                        <button className="text-[11px] font-bold text-primary hover:text-primary/80 transition-colors">Edit List</button>
                    </div>
                    <div className="flex gap-3 overflow-x-auto no-scrollbar py-2 -mx-2 px-2">
                        {[
                            { name: 'Home Clean', icon: '🧹', color: 'from-indigo-500 to-blue-500' },
                            { name: 'Plumber', icon: '🔧', color: 'from-blue-500 to-cyan-500' },
                        ].map((fav, i) => (
                            <motion.button
                                key={i}
                                whileTap={{ scale: 0.95 }}
                                className="flex items-center gap-3 bg-card border border-border/50 p-2 pr-4 rounded-2xl flex-shrink-0 shadow-sm hover:shadow-md transition-all active:bg-secondary/50"
                            >
                                <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${fav.color} flex items-center justify-center text-lg text-white shadow-lg`}>
                                    {fav.icon}
                                </div>
                                <span className="text-xs font-bold text-foreground">{fav.name}</span>
                            </motion.button>
                        ))}
                        <button className="flex items-center gap-3 bg-secondary/30 border border-dashed border-border p-2 pr-4 rounded-2xl flex-shrink-0 hover:bg-secondary/50 transition-colors group">
                            <div className="w-10 h-10 rounded-xl bg-secondary flex items-center justify-center group-hover:bg-background transition-colors">
                                <Plus className="w-5 h-5 text-muted-foreground" />
                            </div>
                            <span className="text-xs font-bold text-muted-foreground">Add New</span>
                        </button>
                    </div>
                </div>

                {/* Services Grid */}
                <div className="mb-2">
                    <h2 className="text-sm font-bold text-foreground mb-4">Categories</h2>
                    <div className="grid grid-cols-4 gap-4">
                        {[
                            { name: 'Plumber', icon: '🔧', color: 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400' },
                            { name: 'Electric', icon: '⚡', color: 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400' },
                            { name: 'Cleaner', icon: '🧹', color: 'bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400' },
                            { name: 'Painter', icon: '🎨', color: 'bg-pink-100 text-pink-600 dark:bg-pink-900/30 dark:text-pink-400' },
                            { name: 'Wood', icon: '🪚', color: 'bg-orange-100 text-orange-600 dark:bg-orange-900/30 dark:text-orange-400' },
                            { name: 'Garden', icon: '🌿', color: 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400' },
                            { name: 'Tech', icon: '💻', color: 'bg-indigo-100 text-indigo-600 dark:bg-indigo-900/30 dark:text-indigo-400' },
                            { name: 'More', icon: '➕', color: 'bg-secondary text-foreground' },
                        ].map((service) => (
                            <motion.button
                                key={service.name}
                                whileTap={{ scale: 0.9 }}
                                onClick={() => {
                                    if (service.name === 'More') router.push('/jobs');
                                    else router.push(`/post-job?category=${encodeURIComponent(service.name.toUpperCase())}`);
                                }}
                                className="flex flex-col items-center gap-2 group"
                            >
                                <div className={cn("w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-sm transition-all group-hover:-translate-y-1 group-hover:shadow-md border border-transparent group-hover:border-border/50", service.color)}>
                                    {service.icon}
                                </div>
                                <span className="text-[10px] font-bold text-muted-foreground group-hover:text-foreground transition-colors">{service.name}</span>
                            </motion.button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Stats Overview */}
            <div className="px-6 mb-8 pt-2">
                <div className="bg-card rounded-[2rem] p-6 shadow-premium border border-border/50 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full blur-2xl -mr-8 -mt-8 pointer-events-none"></div>
                    <div className="flex divide-x divide-border/60 relative z-10">
                        <div className="flex-1 pr-4 space-y-1.5">
                            <div className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Total Posted</div>
                            <div className="text-3xl font-black text-foreground">{user.totalPosted}</div>
                            <div className="inline-flex items-center gap-1 bg-emerald-500/10 px-2 py-0.5 rounded-md border border-emerald-500/20">
                                <span className="text-[10px] font-bold text-emerald-500">+12% this month</span>
                            </div>
                        </div>
                        <div className="flex-1 pl-6 space-y-1.5">
                            <div className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Pending Jobs</div>
                            <div className="text-3xl font-black text-foreground">{user.pendingJobs}</div>
                            <div className="inline-flex items-center gap-1 bg-amber-500/10 px-2 py-0.5 rounded-md border border-amber-500/20">
                                <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse"></span>
                                <span className="text-[10px] font-bold text-amber-500">Action Required</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Active Jobs Section */}
            <div className="mb-8">
                <div className="flex justify-between items-center px-6 mb-5">
                    <h3 className="text-lg font-bold text-foreground">Active Jobs</h3>
                    <Button variant="premium" size="sm" className="rounded-xl px-4 h-9 font-bold text-xs gap-1.5 shadow-lg shadow-primary/20" onClick={() => router.push('/post-job')}>
                        <Plus className="h-3.5 w-3.5" />
                        <span>New Job</span>
                    </Button>
                </div>
                <div className="flex overflow-x-auto space-x-5 px-6 pb-6 no-scrollbar snap-x snap-mandatory">
                    {activeJobs.map((job) => (
                        <motion.div
                            key={job.id}
                            whileTap={{ scale: 0.98 }}
                            onClick={() => router.push(`/tracking/${job.id}`)}
                            className="flex-shrink-0 w-[260px] bg-card rounded-[2rem] p-4 shadow-sm border border-border hover:shadow-premium transition-all cursor-pointer snap-center group"
                        >
                            <div className="relative rounded-2xl overflow-hidden h-40 w-full mb-4">
                                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent z-10" />
                                <img src={job.image} alt={job.title} className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-500" />
                                <div className="absolute top-3 left-3 z-20">
                                    <span className="bg-white/90 dark:bg-black/80 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-bold tracking-wide text-foreground shadow-sm">
                                        {job.status}
                                    </span>
                                </div>
                                <div className="absolute bottom-3 left-3 z-20 flex items-center text-white/90 text-xs font-bold">
                                    <Clock className="h-3.5 w-3.5 mr-1.5" />
                                    {job.dueDate}
                                </div>
                            </div>
                            <div className="space-y-3 px-1">
                                <h4 className="font-bold text-foreground leading-snug line-clamp-1">{job.title}</h4>
                                <div className="space-y-2">
                                    <div className="flex justify-between text-[11px] font-bold">
                                        <span className="text-muted-foreground">Completion</span>
                                        <span className="text-primary">{job.progress}%</span>
                                    </div>
                                    <div className="h-2.5 bg-secondary rounded-full overflow-hidden">
                                        <motion.div
                                            initial={{ width: 0 }}
                                            animate={{ width: `${job.progress}%` }}
                                            transition={{ duration: 1, delay: 0.2 }}
                                            className="h-full bg-gradient-to-r from-primary to-purple-500 rounded-full"
                                        />
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    ))}
                    {/* Add Placeholder for "View All" */}
                    <div className="flex-shrink-0 w-[100px] flex flex-col items-center justify-center snap-center">
                        <button className="w-14 h-14 rounded-full bg-secondary flex items-center justify-center text-muted-foreground hover:bg-secondary/80 hover:scale-110 transition-all">
                            <ChevronRight className="w-6 h-6" />
                        </button>
                        <span className="text-xs font-bold text-muted-foreground mt-2">View All</span>
                    </div>
                </div>
            </div>
        </div>
    );
}
